import NetInfo from '@react-native-community/netinfo';

const MAX_RETRY = 3;
const RETRY_DELAY = 1000; // 1 seconde

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const waitForConnection = async (): Promise<boolean> => {
  const netInfo = await NetInfo.fetch();
  if (netInfo.isConnected && netInfo.isInternetReachable) return true;

  return new Promise((resolve) => {
    const unsubscribe = NetInfo.addEventListener(state => {
      if (state.isConnected && state.isInternetReachable) {
        unsubscribe();
        resolve(true);
      }
    });
    // Timeout après 30 secondes
    setTimeout(() => {
      unsubscribe();
      resolve(false);
    }, 30000);
  });
};

apiClient.interceptors.response.use(
  (response) => response,
  async (error) => {
    const originalRequest = error.config;

    if (error.response?.status === 401 && !originalRequest._retry) {
      originalRequest._retry = true;

      // Attendre la connexion
      const isConnected = await waitForConnection();
      if (!isConnected) {
        // Hors ligne : stocker l'action pour plus tard
        await storeOfflineAction('ADD_TO_CART', originalRequest.data);
        return Promise.reject(new Error('Hors ligne, action stockée'));
      }

      // Tentatives de refresh avec backoff
      for (let attempt = 1; attempt <= MAX_RETRY; attempt++) {
        try {
          const refreshToken = await AsyncStorage.getItem('refreshToken');
          const response = await axios.post('/auth/refresh', { refreshToken });
          const { accessToken } = response.data;
          await AsyncStorage.setItem('authToken', accessToken);
          originalRequest.headers.Authorization = `Bearer ${accessToken}`;
          return apiClient(originalRequest);
        } catch (refreshError) {
          if (attempt === MAX_RETRY) {
            // Échec définitif → déconnexion
            await AsyncStorage.multiRemove(['authToken', 'refreshToken']);
            return Promise.reject(refreshError);
          }
          // Backoff exponentiel
          await sleep(RETRY_DELAY * Math.pow(2, attempt - 1));
        }
      }
    }

    return Promise.reject(error);
  }
);
